/* Timeline of Events Visual LESS Stylesheet */
.timeline-visual-wrapper {
  font-family: 'Segoe UI', -apple-system, BlinkMacSystemFont, 'Inter', 'Roboto', sans-serif;
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  background-color: #ffffff;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.timeline-visual-wrapper ::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
.timeline-visual-wrapper ::-webkit-scrollbar-track {
  background: #f5f5f5;
  border-radius: 3px;
}
.timeline-visual-wrapper ::-webkit-scrollbar-thumb {
  background: #cccccc;
  border-radius: 3px;
}
.timeline-visual-wrapper ::-webkit-scrollbar-thumb:hover {
  background: #aaaaaa;
}
.timeline-container {
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  overflow: hidden;
}
.label-panel-container {
  display: flex;
  flex-direction: column;
  border-right: 2px solid #e0e0e0;
  background-color: #ffffff;
  z-index: 10;
  box-sizing: border-box;
  overflow: visible;
}
.label-row {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  flex-shrink: 0;
  box-sizing: border-box;
  transition: background-color 0.15s ease-in-out, opacity 0.15s ease-in-out;
  background-color: #ffffff;
}
.label-row .cell {
  padding: 0 8px;
  box-sizing: border-box;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-family: inherit;
  flex-shrink: 0;
  display: flex;
  align-items: center;
}
.label-row .name-cell {
  flex-grow: 0;
  flex-shrink: 0;
}
.label-row.zebra-row {
  background-color: #fafbfc;
}
.label-row.event-row.enable-hover-highlight:hover {
  background-color: var(--row-hover-bg, #f4f7fe) !important;
}
.label-row.selected-row:hover {
  filter: brightness(0.95);
}
.label-row.keyboard-focused {
  outline: 2px dashed #0d6efd !important;
  outline-offset: -2px;
}
.column-resize-handle {
  position: absolute;
  top: 0;
  right: -3px;
  width: 6px;
  height: 100%;
  cursor: col-resize;
  z-index: 25;
  user-select: none;
}
.column-resize-handle:hover,
.column-resize-handle.dragging {
  background-color: #0d6efd;
}
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 15;
}
.timeline-axis-header-sticky {
  box-sizing: border-box;
  overflow: hidden;
}
.category-header-row {
  transition: background-color 0.15s ease-in-out;
}
.category-header-row:hover {
  filter: brightness(0.97);
}
.category-header-row .collapse-toggle {
  display: inline-block;
  transition: transform 0.2s ease-in-out;
  user-select: none;
}
.timeline-main-viewport {
  flex: 1 1 auto;
  overflow: hidden;
  position: relative;
  border-top: 1px solid #f0f0f0;
}
.timeline-scroll-viewport {
  width: 100%;
  height: 100%;
  flex: 1 1 auto;
  min-width: 0;
}
.timeline-right-plot {
  display: flex;
  flex-direction: column;
  background-color: #ffffff;
}
.timeline-axis-ticks {
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
}
.timeline-axis-ticks .axis-row {
  display: flex;
  flex-direction: row;
  width: 100%;
  box-sizing: border-box;
}
.timeline-axis-ticks .axis-cell {
  font-family: inherit;
  color: #555555;
}
.timeline-svg .event-marker-group {
  outline: none !important;
  box-shadow: none !important;
  transition: transform 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275), filter 0.2s ease;
  transform-origin: center;
}
.timeline-svg .event-marker-group:focus,
.timeline-svg .event-marker-group *:focus {
  outline: none !important;
  box-shadow: none !important;
}
.timeline-svg .event-marker-group circle,
.timeline-svg .event-marker-group polygon,
.timeline-svg .event-marker-group rect,
.timeline-svg .event-marker-group path {
  transition: stroke-width 0.2s ease, filter 0.2s ease;
}
.timeline-svg .event-marker-group:hover {
  filter: drop-shadow(0px 2px 4px rgba(0, 0, 0, 0.15));
}
.timeline-svg .event-marker-group:hover circle,
.timeline-svg .event-marker-group:hover polygon,
.timeline-svg .event-marker-group:hover rect,
.timeline-svg .event-marker-group:hover path {
  stroke-width: 1.5px;
}
.timeline-svg .marker-glow {
  opacity: 0;
  transition: opacity 0.15s ease-in-out;
}
.timeline-svg .event-marker-group:hover .marker-glow {
  opacity: 0.8;
  animation: glow-pulse 2s infinite ease-in-out;
}
.timeline-legend-container.side-legend {
  border-bottom: 0;
  border-right: 1px solid #eeeeee;
  max-width: 180px;
  overflow: auto;
  flex: 0 0 auto;
}
@keyframes glow-pulse {
  0% {
    opacity: 0.3;
    transform: scale(1);
  }
  50% {
    opacity: 0.8;
    transform: scale(1.05);
  }
  100% {
    opacity: 0.3;
    transform: scale(1);
  }
}
.badge {
  display: inline-block;
  font-weight: 700;
  line-height: 1;
  text-align: center;
  white-space: nowrap;
  vertical-align: baseline;
  user-select: none;
}
.timeline-resizer {
  width: 5px;
  cursor: col-resize;
  background-color: #eeeeee;
  border-left: 1px solid #e0e0e0;
  border-right: 1px solid #ffffff;
  z-index: 50;
  transition: background-color 0.2s ease;
  user-select: none;
  flex-shrink: 0;
  position: relative;
}
.timeline-resizer:hover,
.timeline-resizer.dragging {
  background-color: #0d6efd;
  border-left-color: #0d6efd;
  border-right-color: #0d6efd;
}
